import { resolveShorthandOld } from '../shared/slot';
import { forwardHTMLRef } from '../util/forwardRef';
import type { MetricsProps } from './Metrics';
import * as React from 'react';
import { ResizeObserver } from '@universe-design/react-utilities';
import { useMetricsGroupContextSelector } from './MetricsGroup';
import { useMetricsFooterDescendant } from './useMetrics';

type MetricsSecondaryContentProps = Pick<MetricsProps, 'footer'>;

export const MetricsFooter = forwardHTMLRef<MetricsSecondaryContentProps, 'div'>((props, ref) => {
  const { footer } = props;
  const footerProps = resolveShorthandOld(footer);
  const { index, register } = useMetricsFooterDescendant();
  const recalculateFooterHeights = useMetricsGroupContextSelector(context => context?.recalculateFooterHeights);
  const footerRowMaxHeight = useMetricsGroupContextSelector(context => context?.footerRowInfo?.[index]?.maxHeight);

  return (
    <div ref={ref}>
      <div style={{ height: footerRowMaxHeight }}>
        <ResizeObserver onResize={recalculateFooterHeights}>
          <div ref={register}>{footerProps?.children}</div>
        </ResizeObserver>
      </div>
    </div>
  );
});
